+			if len(resp.SendAs) == 0 {
+				u.Err().Println("No send-as aliases")
+				return nil
+			}
+
+			tw := tabwriter.NewWriter(os.Stdout, 0, 4, 2, ' ', 0)
+			fmt.Fprintln(tw, "EMAIL\tDISPLAY NAME\tDEFAULT\tVERIFIED\tTREAT AS ALIAS")
+			for _, sa := range resp.SendAs {
+				isDefault := ""
+				if sa.IsDefault {
+					isDefault = "yes"
