+		t.Errorf("expected 200, got %d", resp.StatusCode)
+	}
+
+	// After success, failures should be reset
+	if rt.CircuitBreaker.failures != 0 {
+		t.Errorf("expected failures reset to 0, got %d", rt.CircuitBreaker.failures)
+	}
